import React from "react";
import {
  VerticalTimeline,
  VerticalTimelineElement,
} from "react-vertical-timeline-component";
import "react-vertical-timeline-component/style.min.css";

import { FaBriefcase, FaUniversity, FaCloud } from "react-icons/fa";

const experienceData = [
  {
    title: "Senior Product Manager",
    company: "EY",
    date: "2022 - Present",
    icon: <FaBriefcase />,
  },
  {
    title: "Senior Product Manager",
    company: "J.P. Morgan",
    date: "2021 - 2022",
    icon: <FaCloud />,
  },
  {
    title: "Senior Product Manager",
    company: "ExxonMobil",
    date: "2014 - 2021",
    icon: <FaUniversity />,
  },
  {
    title: "Senior Product Owner",
    company: "ExxonMobil",
    date: "2013 - 2014",
    icon: <FaUniversity />,
  },
  {
    title: "Senior Scrum Master",
    company: "ExxonMobil",
    date: "2008 - 2013",
    icon: <FaUniversity />,
  },

  {
    title: "Supervisor",
    company: "IBM",
    date: "2001 - 2008",
    icon: <FaUniversity />,
  },
  {
    title: "Master of Systems Engineering",
    company: "Universidad Tecnologica Nacional (UTN)",
    date: "2001 - 2006",
    icon: <FaUniversity />,
  },

  {
    title: "Microsoft Certified: Azure Fundamentals",
    company: "Azure",
    date: "2021 - 2021",
    icon: <FaUniversity />,
  },

  {
    title: "PMI Agile Certified Practitioner (PMIACP)",
    company: "PMI",
    date: "2019 - 2019",
    icon: <FaUniversity />,
  },

  {
    title: "Certified SAFe® 6 Product Owner/Product Manager",
    company: "Scaled Agile",
    date: "2023 - 2024",
    icon: <FaUniversity />,
  },

  {
    title: "Certified Scrum Product Owner (CSPO)",
    company: "Scrum Alliance",
    date: "2022 - 2024",
    icon: <FaUniversity />,
  },


];

export default function ExperienceTimeline() {
  return (
    <VerticalTimeline>
      {experienceData.map((exp, idx) => (
        <VerticalTimelineElement
          key={idx}
          date={<span style={{ fontWeight: "bold", color: "#6b46c1" }}>{exp.date}</span>}
          iconStyle={{ background: "#6b46c1", color: "#fff" }}
          contentStyle={{ background: "#6b46c1", color: "#fff" }}
          contentArrowStyle={{ borderRight: "7px solid #6b46c1" }}
          icon={exp.icon}
        >
          <h3>{exp.title}</h3>
          <h4>{exp.company}</h4>
          <p>{exp.description}</p>
        </VerticalTimelineElement>
      ))}
    </VerticalTimeline>
  );
}
